import type { AgentTool } from "@mariozechner/pi-agent-core";
import type { HooksConfig } from "./hooks.js";
import type { SkillMetadata } from "./skills.js";
import type { GCToolDefinition } from "./sdk-types.js";
export interface PluginConfigProperty {
    type: "string" | "number" | "boolean";
    description?: string;
    default?: any;
    env?: string;
}
export interface PluginManifest {
    id: string;
    name: string;
    version: string;
    description: string;
    author?: string;
    license?: string;
    provides?: {
        tools?: boolean;
        hooks?: {
            on_session_start?: Array<{
                script: string;
                description?: string;
            }>;
            pre_tool_use?: Array<{
                script: string;
                description?: string;
            }>;
            post_response?: Array<{
                script: string;
                description?: string;
            }>;
            on_error?: Array<{
                script: string;
                description?: string;
            }>;
        };
        skills?: boolean;
        prompt?: string;
    };
    config?: {
        properties?: Record<string, PluginConfigProperty>;
        required?: string[];
    };
    entry?: string;
    engine?: string;
}
export interface PluginConfig {
    enabled?: boolean;
    source?: string;
    version?: string;
    config?: Record<string, any>;
}
export interface MemoryLayerDef {
    name: string;
    path: string;
    description: string;
}
export interface LoadedPlugin {
    manifest: PluginManifest;
    directory: string;
    config: Record<string, any>;
    tools: AgentTool<any>[];
    programmaticTools: GCToolDefinition[];
    hooks: HooksConfig | null;
    skills: SkillMetadata[];
    promptAddition: string;
    memoryLayers: MemoryLayerDef[];
}
